Context.isMandatory:
	var tdate = Services.getValue(RegistrationWritsDate.dataBinding);			    
    if( null == tdate || "" == tdate ) {	return false;}
    var isValid = isValidDate(tdate);			    			    
	return isValid;

Context.isEnabled:
	var tdate = Services.getValue(RegistrationWritsDate.dataBinding);			    
    if( null == tdate || "" == tdate ) {	return false;}
    var isValid = isValidDate(tdate);			    			    
	return isValid;

Context.logic:
var tdate = Services.getValue(RegistrationWritsDate.dataBinding);
var isValid = isValidDate(tdate);
if( !isValid || (null == tdate || "" == tdate ))
{	Services.setValue(ReferenceNumber.dataBinding, "");	}
